/**
 * Black Forest Labs API firewall config generator.
 *
 * Data source: https://docs.bfl.ai/quick_start/generating_images
 *
 * BFL uses an API key in the x-key header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.bfl.ai/quick_start/generating_images";
const PLACEHOLDER_VALUE = "bfl_CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Black Forest Labs API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:bfl",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const bflFirewall = {",
    '  name: "bfl",',
    '  description: "Black Forest Labs API",',
    "  placeholders: {",
    `    BFL_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.bfl.ai",',
    "      auth: {",
    "        headers: {",
    '          "x-key": "${{ secrets.BFL_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://api.eu.bfl.ai",',
    "      auth: {",
    "        headers: {",
    '          "x-key": "${{ secrets.BFL_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://api.us.bfl.ai",',
    "      auth: {",
    "        headers: {",
    '          "x-key": "${{ secrets.BFL_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Black Forest Labs firewall config...");
  const ts = generateTypeScript();
  writeOutput("bfl", ts, import.meta.dirname);
}
